arguments.new_str:
private string CacheResult(ConcurrentDictionary<string, string> cache, string key, string value)
{
    if (cache.Count < MaxCacheSize)
    {
        cache.TryAdd(key, value);
    }

    return value;
}

private static string? ApplyRules(List<InflectionEntry> rules, string word)
{
    for (var i = rules.Count - 1; i >= 0; i--)
    {
        var result = rules[i].Apply(word);
        if (result != null)
        {
            return result;
        }
    }

    return null;
}

/// <summary>
/// Internal rule entry holding a regex and replacement pattern.
/// </summary>
private class InflectionEntry
{
    private readonly Regex _regex;
    private readonly string _replacement;

    public InflectionEntry(string pattern, string replacement)
    {
        _regex = new Regex(pattern, RegexOptions.IgnoreCase);
        _replacement = replacement;
    }

    public string? Apply(string word)
    {
        var result = _regex.Replace(word, _replacement);
        return string.Equals(result, word, StringComparison.Ordinal) ? null : result;
    }
}

