18.     private readonly Dictionary<string, string> _irregularPlurals =
19.         new(StringComparer.OrdinalIgnoreCase);
20.     private readonly Dictionary<string, string> _irregularSingulars =
21.         new(StringComparer.OrdinalIgnoreCase);
22. 
23.     // Cache to avoid repeated regex matching for commonly inflected words
24.     private readonly ConcurrentDictionary<string, string> _pluralCache = new(StringComparer.Ordinal);
25.     private readonly ConcurrentDictionary<string, string> _singularCache = new(StringComparer.Ordinal);
26.     private const int MaxCacheSize = 1024;
27. 
