47.     /// <param name="replacement">The replacement string for generating the plural form.</param>
48.     public void AddPlural(string pattern, string replacement)
49.     {
50.         _uncountables.Remove(pattern);
51.         _uncountables.Remove(replacement);
52.         _plurals.Add(new InflectionEntry(pattern, replacement));
53.         _pluralCache.Clear();
54.     }
