     /// Returns the plural form of the given word using registered rules.
     /// </summary>
     /// <param name="word">The word to pluralize.</param>
     /// <returns>The plural form of the word.</returns>
     public string Pluralize(string word)
     {
         if (string.IsNullOrWhiteSpace(word))
         {
             return word;
         }

         if (_pluralCache.TryGetValue(word, out var cached))
         {
             return cached;
         }

         if (_uncountables.Contains(word))
         {
             return word;
         }

         if (_irregularPlurals.TryGetValue(word, out var irregularPlural))
         {
             return CacheResult(_pluralCache, word, irregularPlural);
         }

         var result = ApplyRules(_plurals, word) ?? word;
         return CacheResult(_pluralCache, word, result);
